/// Pre-processes XML content to resolve external entity declarations in the DOCTYPE.
/// This manually parses ENTITY declarations and substitutes entity references.
fn preprocess_entities(xml_content: &str) -> Result<String, String> {
    let mut entities: HashMap<String, String> = HashMap::new();

    // Parse ENTITY declarations from DOCTYPE
    if let Some(doctype_start) = xml_content.find("<!DOCTYPE") {
        if let Some(doctype_end) = xml_content[doctype_start..].find(']') {
            let doctype_section = &xml_content[doctype_start..doctype_start + doctype_end + 1];

            // Find all ENTITY declarations
            let mut search_pos = 0;
            while let Some(entity_start) = doctype_section[search_pos..].find("<!ENTITY") {
                let abs_start = search_pos + entity_start;
                if let Some(entity_end) = doctype_section[abs_start..].find('>') {
                    let entity_decl = &doctype_section[abs_start..abs_start + entity_end + 1];
                    parse_entity_declaration(entity_decl, &mut entities)?;
                    search_pos = abs_start + entity_end + 1;
                } else {
                    break;
                }
            }
        }
    }

    // Substitute entity references in the XML content
    let mut result = xml_content.to_string();

    // Remove the DOCTYPE declaration for clean parsing
    if let Some(doctype_start) = result.find("<!DOCTYPE") {
        if let Some(doctype_end) = result[doctype_start..].find(">]>") {
            result = format!(
                "{}{}",
                &result[..doctype_start],
                &result[doctype_start + doctype_end + 3..]
            );
        } else if let Some(doctype_end) = result[doctype_start..].find('>') {
            result = format!(
                "{}{}",
                &result[..doctype_start],
                &result[doctype_start + doctype_end + 1..]
            );
        }
    }

    // Replace entity references with their resolved values
    for (name, value) in &entities {
        let entity_ref = format!("&{};", name);
        result = result.replace(&entity_ref, value);
    }

    Ok(result)
}

/// Parses a single ENTITY declaration and resolves it
fn parse_entity_declaration(
    decl: &str,
    entities: &mut HashMap<String, String>,
) -> Result<(), String> {
    let trimmed = decl.trim();

    // Remove <!ENTITY and trailing >
    let inner = trimmed
        .strip_prefix("<!ENTITY")
        .and_then(|s| s.strip_suffix('>'))
        .map(|s| s.trim())
        .ok_or("Invalid ENTITY declaration")?;

    let parts: Vec<&str> = inner.splitn(3, char::is_whitespace).collect();

    if parts.len() < 2 {
        return Err("Malformed ENTITY declaration".to_string());
    }

    let entity_name = parts[0].trim();
    let remaining = parts[1..].join(" ");
    let remaining = remaining.trim();

    if remaining.starts_with("SYSTEM") {
        // External entity - resolve by reading the file
        // This supports external entity references for document reusability
        let system_part = remaining.strip_prefix("SYSTEM").unwrap().trim();
        let system_id = system_part
            .trim_matches('"')
            .trim_matches('\'')
            .to_string();

        let content = resolve_external_entity(&system_id)?;
        entities.insert(entity_name.to_string(), content);
    } else if remaining.starts_with("PUBLIC") {
        // Public external entity
        let parts: Vec<&str> = remaining.splitn(3, '"').collect();
        if parts.len() >= 4 {
            let system_id = parts[3].trim().trim_matches('"').trim_matches('\'');
            let content = resolve_external_entity(system_id)?;
            entities.insert(entity_name.to_string(), content);
        }
    } else {
        // Internal entity - extract the value
        let value = remaining
            .trim_matches('"')
            .trim_matches('\'')
            .to_string();
        entities.insert(entity_name.to_string(), value);
    }

    Ok(())
}

